#!/usr/bin/env python3
# Generated By: Claude Code (Claude Opus 4.6)
"""Claude Code status line.

Output: Context | <time-to-reset>: <pct>% | ... (freshness) | Model

Quota labels show time remaining until reset, e.g.:
  3h4m: 20% | 4d12h: 4% (0s)
At most 2 units of precision: d+h, h+m, m+s, or single unit.

Quota utilization is fetched from the Anthropic OAuth usage API.
Cached for 2 minutes; on 429/error, stale cache is used.
Freshness indicator shows age and fetch status:
  (2m)  = data is 2 minutes old, last fetch succeeded
  (!5m) = data is 5 minutes old, last fetch failed

Session cost from Claude Code stdin (cost.total_cost_usd).
"""

import json
import logging
import logging.handlers
import sys
import time
import urllib.request
import urllib.error
from datetime import datetime, timezone
from pathlib import Path

ANSI_RED = "\033[31m"
ANSI_YELLOW = "\033[33m"
ANSI_GREEN = "\033[32m"
ANSI_RESET = "\033[0m"

USAGE_CACHE_TTL_SECONDS = 120
USAGE_CACHE_DIR = Path.home() / ".claude" / "statusline-cache"
USAGE_CACHE_FILE = USAGE_CACHE_DIR / "oauth_usage.json"
LOG_FILE = USAGE_CACHE_DIR / "statusline.log"
CREDENTIALS_FILE = Path.home() / ".claude" / ".credentials.json"

logger = logging.getLogger("statusline")
_log_configured = False


def _configure_logging():
    global _log_configured
    if _log_configured:
        return
    _log_configured = True
    try:
        USAGE_CACHE_DIR.mkdir(parents=True, exist_ok=True)
        handler = logging.handlers.RotatingFileHandler(
            str(LOG_FILE),
            maxBytes=256 * 1024,
            backupCount=1,
            encoding="utf-8",
        )
        handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
        logger.addHandler(handler)
        logger.setLevel(logging.DEBUG)
    except OSError:
        pass


# source: reddit.com/r/ClaudeAI/comments/1rqnryw
USAGE_API_URL = "https://api.anthropic.com/api/oauth/usage"


def format_duration(seconds):
    """Format seconds as compact duration, max 2 units.

    Build full d+h+m+s, then truncate after the second unit.
    """
    seconds = max(0, int(seconds))
    days = seconds // 86400
    hours = (seconds % 86400) // 3600
    minutes = (seconds % 3600) // 60
    secs = seconds % 60

    parts = []
    if days:
        parts.append(f"{days}d")
    if hours:
        parts.append(f"{hours}h")
    if minutes:
        parts.append(f"{minutes}m")
    if secs or not parts:
        parts.append(f"{secs}s")
    return "".join(parts[:2])


def colorize_pct(pct):
    """Return pct formatted as a string with ANSI color based on magnitude.

    Green  < 50%
    Yellow 50-79%
    Red    >= 80%
    """
    value = f"{pct:.0f}%"
    if pct >= 80:
        color = ANSI_RED
    elif pct >= 50:
        color = ANSI_YELLOW
    else:
        color = ANSI_GREEN
    return f"{color}{value}{ANSI_RESET}"


def format_remaining(resets_at):
    """Parse resets_at ISO timestamp, return compact time remaining."""
    if not resets_at:
        return None
    try:
        reset_dt = datetime.fromisoformat(resets_at)
        now = datetime.now(timezone.utc)
        remaining = int((reset_dt - now).total_seconds())
        if remaining <= 0:
            return "0s"
        return format_duration(remaining)
    except (ValueError, OverflowError):
        return None


def get_oauth_token():
    try:
        data = json.loads(CREDENTIALS_FILE.read_text(encoding="utf-8"))
        return data["claudeAiOauth"]["accessToken"]
    except (OSError, KeyError, json.JSONDecodeError) as e:
        logger.error("Failed to read OAuth token: %s", e)
        return None


def fetch_usage():
    token = get_oauth_token()
    if not token:
        logger.warning("No OAuth token available, skipping fetch")
        return None

    req = urllib.request.Request(USAGE_API_URL)
    req.add_header("Authorization", f"Bearer {token}")
    req.add_header("anthropic-beta", "oauth-2025-04-20")

    try:
        with urllib.request.urlopen(req, timeout=5) as resp:
            data = json.loads(resp.read())
            logger.debug("Fetch succeeded")
            return data
    except urllib.error.HTTPError as e:
        body = ""
        try:
            body = e.read().decode()[:200]
        except Exception:
            pass
        logger.error("HTTP %d %s: %s", e.code, e.reason, body)
        return None
    except (urllib.error.URLError, OSError, json.JSONDecodeError) as e:
        logger.error("Fetch failed: %s: %s", type(e).__name__, e)
        return None


def _read_cache():
    """Read and migrate cache file. Returns dict or None."""
    if not USAGE_CACHE_FILE.exists():
        return None
    try:
        cached = json.loads(USAGE_CACHE_FILE.read_text(encoding="utf-8"))
    except (json.JSONDecodeError, OSError):
        return None
    # Migrate old single-letter keys to new schema
    if "v" in cached and "response_data" not in cached:
        cached = {
            "response_data": cached["v"],
            "last_success_at": cached.get("t", 0),
            "last_attempt_at": cached.get("t", 0),
            "consecutive_failures": 0,
        }
    return cached


def _write_cache(cache_dict):
    """Write cache dict to disk."""
    try:
        USAGE_CACHE_FILE.parent.mkdir(parents=True, exist_ok=True)
        USAGE_CACHE_FILE.write_text(json.dumps(cache_dict), encoding="utf-8")
    except OSError:
        pass


MAX_COOLDOWN_SECONDS = 3600


def get_usage():
    """Return (usage_dict, age_seconds, stale) or (None, 0, False)."""
    now = time.time()
    cached = _read_cache()

    if cached:
        age = now - cached.get("last_success_at", 0)
        if age < USAGE_CACHE_TTL_SECONDS:
            return cached.get("response_data"), age, False

        # Stale — check if we should skip fetch due to backoff cooldown
        failures = cached.get("consecutive_failures", 0)
        if failures > 0:
            cooldown = min(
                USAGE_CACHE_TTL_SECONDS * (2**failures), MAX_COOLDOWN_SECONDS
            )
            since_last_attempt = now - cached.get("last_attempt_at", 0)
            if since_last_attempt < cooldown:
                logger.info(
                    "Backoff: skipping fetch, %d consecutive failures, "
                    "cooldown %.0fs, %.0fs remaining",
                    failures,
                    cooldown,
                    cooldown - since_last_attempt,
                )
                return cached.get("response_data"), age, True

    result = fetch_usage()

    if result is not None:
        _write_cache(
            {
                "response_data": result,
                "last_success_at": now,
                "last_attempt_at": now,
                "consecutive_failures": 0,
            }
        )
        return result, 0, False

    # Fetch failed — update attempt tracking, preserve stale data
    if cached:
        cached["last_attempt_at"] = now
        cached["consecutive_failures"] = cached.get("consecutive_failures", 0) + 1
        _write_cache(cached)
        age = now - cached.get("last_success_at", 0)
        logger.warning(
            "Fetch failed, consecutive_failures=%d, serving stale cache (%.0fs old)",
            cached["consecutive_failures"],
            age,
        )
        return cached.get("response_data"), age, True

    return None, 0, False


def main():
    _configure_logging()
    try:
        data = json.load(sys.stdin)
    except (json.JSONDecodeError, EOFError):
        print("Claude Code")
        return

    model = data.get("model", {}).get("display_name", "Claude")
    parts = []

    ctx = data.get("context_window", {})
    used_pct = ctx.get("used_percentage")
    if used_pct is not None:
        parts.append(f"Context: {colorize_pct(used_pct)}")

    usage, age_seconds, stale = get_usage()
    if usage:
        for bucket in ("five_hour", "seven_day"):
            entry = usage.get(bucket)
            if not entry:
                continue
            pct = entry.get("utilization")
            if pct is None:
                continue
            label = format_remaining(entry.get("resets_at"))
            if label is None:
                label = "5h" if bucket == "five_hour" else "1w"
            parts.append(f"{label}: {colorize_pct(pct)}")

        age_str = format_duration(age_seconds)
        if stale:
            parts.append(f"({ANSI_RED}!{age_str}{ANSI_RESET})")
        else:
            parts.append(f"({age_str})")

    # When invoked directly (python3 path/to/statusline.py), the parent
    # of scripts/ must be on sys.path for the package import to work.
    _scripts_parent = str(Path(__file__).resolve().parent.parent)
    if _scripts_parent not in sys.path:
        sys.path.insert(0, _scripts_parent)
    from scripts.session_tracker import get_daily_cost, get_project_cost, track_session

    track_session(data)
    cost = (data.get("cost") or {}).get("total_cost_usd")
    parts.append(f"Session: ${cost:.2f}" if cost is not None else "Session: $0.00")
    daily = get_daily_cost()
    parts.append(f"Today: ${daily:.2f}")

    project_dir = (data.get("workspace") or {}).get("project_dir")
    if project_dir:
        proj_cost = get_project_cost(project_dir)
        parts.append(f"Project: ${proj_cost:.2f}")

    parts.append(f"Model: {model}")
    print(" | ".join(parts))


if __name__ == "__main__":
    try:
        main()
    except Exception:
        _configure_logging()
        logger.exception("statusline crashed")
        print(f"{ANSI_RED}!ERR check {LOG_FILE}{ANSI_RESET}")
